// =====================================================
// KINGDOM OF ELDGATE — project template map.
//
// Demonstrates everything MapLang can do, composed
// deliberately rather than thrown together:
//
//   - import three part libraries (buildings, town, featured)
//   - place reusable parts (Castle, Cottage, Inn, Fountain,
//     MarketStall) at deliberate positions
//   - edge crossings to neighboring regions (harbor & farmstead)
//   - portals into interiors (castle, cottage)
//   - animated tiles (water, torches, chicken, cow)
//
// Read the scene:  central crossroads under the king's castle,
// a fountain plaza, two market stalls, three cottages, an inn,
// a forest framing the south-east, a pond in the south-west.
// =====================================================

import "buildings.map";   // Castle, Watchtower
import "town.map";        // Cottage, WoodCottage, Inn, Shop, Garden
import "featured.map";    // Fountain, MarketStall, Lighthouse, etc.

map Kingdom {
  size 40, 24;

  // Walk west off the edge → Harbor; walk east → Farmstead.
  neighbor west "harbor.map";
  neighbor east "farmstead.map";

  // ─── The Castle dominates the north ───
  place Castle at (12,0);

  // ─── Main road: stone highway east-west ───
  row STONE from (0,13) to (39,13);
  row STONE from (0,14) to (39,14);

  // ─── Vertical road: south gate up to castle gate ───
  row STONE from (19,12) to (19,23);
  row STONE from (20,12) to (20,23);

  // ─── South gate, flanked by green banners ───
  tile ARCH_STONE   at (19,23);
  tile ARCH_STONE   at (20,23);
  tile BANNER_GREEN at (18,23);
  tile BANNER_GREEN at (21,23);

  // ─── Banners flanking the castle gate (outside) ───
  tile BANNER_TEAL at (17,12);
  tile BANNER_TEAL at (22,12);

  // ─── Fountain plaza, west of the crossroads ───
  place Fountain at (14,17);

  // ─── Market stalls, east of the crossroads ───
  place MarketStall at (23,17);
  place MarketStall at (27,17);

  // ─── Cottages on the west ───
  place Cottage     at (1,17);   // SW cottage
  place WoodCottage at (6,18);   // central-south wood cottage

  // ─── Inn on the east ───
  place Inn at (32,17);

  // ─── Portals into interiors ───
  // Castle's gate (Castle's part-local gate at (7,11),(8,11) → world (19,11),(20,11))
  portal at (19,11) -> "castle_interior.map";
  portal at (20,11) -> "castle_interior.map";

  // The wood cottage's door (part-local (1,2) → world (7,20))
  portal at (7,20) -> "cottage_interior.map";

  // ─── Forest cluster framing the south-east ───
  tile TREE_OAK  at (33,21);
  tile TREE_PINE at (35,19);
  tile TREE_OAK  at (37,21);
  tile TREE_PINE at (38,17);

  // ─── Tree clusters in the north corners (outside castle) ───
  tile TREE_PINE at (1,1);
  tile TREE_OAK  at (3,3);
  tile TREE_PINE at (1,8);
  tile TREE_OAK  at (37,2);
  tile TREE_PINE at (38,8);

  // ─── A small pond in the south-west ───
  fill WATER from (4,21) to (5,23);
  tile ROCK at (4,21);
  tile MUSHROOM at (3,22);

  // ─── Banners flanking the road approaches ───
  tile BANNER_GREEN at (9,13);
  tile BANNER_GREEN at (29,13);

  // ─── Signposts at the key intersections ───
  tile SIGNPOST at (1,12);    // pointing west to Harbor
  tile SIGNPOST at (38,12);   // pointing east to Farmstead
  tile SIGNPOST at (18,22);   // by the south gate

  // ─── Wayside flora ───
  tile FLOWER   at (12,16);
  tile FLOWER   at (28,16);
  tile MUSHROOM at (32,12);
  tile MUSHROOM at (8,12);

  // Player spawns just inside the south gate, on the road.
  player at (19,22);
}
